                                    close()
                                }
                            )
                            .background(
                                brush = Brush.verticalGradient(
                                    colors = listOf(
                                        Turquoise300.copy(alpha = 0.7f), // Más transparente para el efecto de cruce
                                        Turquoise400.copy(alpha = 0.5f)
                                    )
                                )
                            )
                    )

                    // Solo el botón de menú dentro de las ondas
                    Column {
                        // Top bar integrado en el header
